import React, { useEffect, useRef, useState } from "react";
import Header from "./header";
import Footer from "./footer";
import PoleList from "./poleList";
import "../Css/App.css";
import { useLocation, useNavigate } from "react-router-dom";

export default function Body(){
  
  const Navigate = useNavigate();
  const location = useLocation();
  const {loginck} = location.state || {};
  const {insertPole} = location.state || {};

  const [input,setinput] = useState("");
  const [ckLogin,setckLogin] = useState(false);

    useEffect(()=>{
      if(!loginck) setckLogin(false);
      else setckLogin(true);
      if(insertPole){
      const pList = {
        id: nextId.current,
        poleNum: insertPole.poleNum,
        poleDate: [insertPole.poleDate,],
        poleTilt: [90,],
        poleAdmin: insertPole.poleAdmin,
        poleImg: insertPole.poleImg,
      }
      setPole([...Pole,pList])
      nextId.current +=1;
    }
    },[]);

    const [Pole,setPole] = useState([
      {
        id:"0",
        poleNum:"9215W452",
        poleDate:["05-06","05-07","05-08","05-09","05-10"],
        poleTilt:[90,87,80,71,50],
        poleAdmin:"성민",
        poleImg:"https://search.pstatic.net/common/?src=http%3A%2F%2Fblogfiles.naver.net%2FMjAyMTA4MTBfMTQ5%2FMDAxNjI4NjAxMDk0MzQw.nx2K0837aBAOqQa__JVgiqgG1XqoLnCN4bOzyO1AYFMg.-bne_M1HKBh5_33Qn-9z5qo3NiieR-HCsFWRn8LIRlEg.JPEG.kokurean%2FKakaoTalk_20210810_211011641_02.jpg&type=a340",
    },
    {
        id:"1",
        poleNum:"9451W433",
        poleDate:["05-06","05-07","05-08","05-09","05-10"],
        poleTilt:[90,88,85,81,90],
        poleAdmin:"성민",
        poleImg:"https://search.pstatic.net/common/?src=http%3A%2F%2Fblogfiles.naver.net%2Fdata32%2F2008%2F2%2F21%2F126%2Fimg_2918_chonammin.jpg&type=a340",
    },
    {
        id:"2",
        poleNum:"3215W489",
        poleDate:["05-06","05-07","05-08","05-09","05-10"],
        poleTilt:[90,50,90,90,90],
        poleAdmin:"성민",
        poleImg:"https://search.pstatic.net/common/?src=http%3A%2F%2Fblogfiles.naver.net%2FMjAyMTExMDlfNTYg%2FMDAxNjM2NDUzMzY0MDQ2.dXsGiDkSbMUkj_fbPyzE1OtPO43kPmpnQN6AwSr6Ve0g.oTttD2vOFPlFmCBd1R5vLqWJqpFGxnwQnGSGkbDOxIQg.JPEG.aramviola%2F211109_%25C0%25FC%25BA%25BF%25B4%25EB.jpg&type=a340",
    },
    {
        id:"3",
        poleNum:"5216W427",
        poleDate:["05-06","05-07","05-08","05-09","05-10"],
        poleTilt:[90,88,87,88,85],
        poleAdmin:"성민",
        poleImg:"https://search.pstatic.net/common/?src=http%3A%2F%2Fblogfiles.naver.net%2F20091005_192%2Filyonge2_1254670305568glDaP_jpg%2F%25B9%25AB%25C1%25A6-3_%25BA%25B9%25BB%25E7_ilyonge2.jpg&type=a340",
    },
    {
        id:"4",
        poleNum:"1115W452",
        poleDate:["05-06","05-07","05-08","05-09","05-10"],
        poleTilt:[90,87,80,71,90],
        poleAdmin:"성민",
        poleImg:"https://search.pstatic.net/common/?src=http%3A%2F%2Fblogfiles.naver.net%2FMjAyMTA1MThfMjcw%2FMDAxNjIxMzE3ODUwNzAw.FrKtS_pRGQtuagqd6rHdT50H8XUAsNBY6flu4xmKypUg.I6HxLtIeSkgDQeQpqlNtE9nkTgGRrZqSt8xc5I90GQEg.JPEG.x1212156%2Fphoto-1600677021924-6c33771c698e.jpg&type=a340",
    },
  ]);

    const nextId = useRef(5);
      
    function updateRef(e) {
      if(e.key === "Enter"){
        setinput(e.target.value)
      }
    }
  
    const keys = ["poleNum","poleAdmin"];
    
    const search = (pole) => {
      return pole.filter((item) => 
      keys.some(key => item[key].includes(input))
      );
    }
  
    const onChart = (e) =>{
      Navigate("/chart",{state: {poleInfo:Pole[e.target.value]}})
    }

    const onInfo = (e) =>{
      Navigate("/info",{state: {poleInfo:Pole[e.target.value]}})
  }
    return(
        <div>
            <Header ckLogin={ckLogin} setckLogin={setckLogin}/>
            <PoleList index={search(Pole)} onKeyDown={updateRef} onChart={onChart} onInfo={onInfo} insertPole={insertPole} />
            <Footer />
        </div>
    )
}